  ('social-worker-moex-01202', 'social-worker', 'social-worker-moex-110-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '一個方案往往涉及到許多利害關係人，為達到評估的目的，需要確認利害關係人，「確認利害關係 人」係屬於方案管理過程中那個階段重要的評估工作？', '["開始階段", "準備階段", "執行階段", "結束階段"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:07+00:00", "source_pdf_sha1": "5eb261e734f1", "answer_pdf_sha1": "0af20b0ec580", "source_family": "moex-gov-tw", "moex": {"exam_code": "110030", "c": "105", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "110", "exam_name": "110年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
