  ('social-worker-moex-01204', 'social-worker', 'social-worker-moex-110-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '在社會服務的方案評估中，包括對服務對象及服務的評估，下列何種方式主要是針對「服務對象」 所進行的評估？', '["投入評估", "形成評估", "產出評估", "效果評估"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:07+00:00", "source_pdf_sha1": "5eb261e734f1", "answer_pdf_sha1": "0af20b0ec580", "source_family": "moex-gov-tw", "moex": {"exam_code": "110030", "c": "105", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "110", "exam_name": "110年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
